insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0001', 'offering-001', '历史共享表', '不确定', '不确定', '不确定', 4, '大水课', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0002', 'offering-002', '历史共享表', '不确定', '不确定', '不确定', 5, '没上过TIC但是曾老师是我的新生导师，有和几个同学一起约饭聊过，曾老师是做类脑计算材料的，人也很好，对这方面感兴趣可冲', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0003', 'offering-007', '历史共享表', '不确定', '不确定', '不确定', 4, '（选的时候叫增材制造🤔️），喜欢熬夜者的天堂（通宵那种），但确实能学到东西，挺充实的', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0004', 'offering-007', '历史共享表', '不确定', '不确定', '不确定', 4, '这林涛非常坏，指导学生做实验的时候不告诉学生自己现有的研究成果，让学生自己基本上从零开始摸索，当然这应该是林涛独特的教学观念，好在林涛会请实验做的晚的同学吃外卖，贪吃的同学可以入', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0005', 'offering-008', '历史共享表', '重', '不确定', '不确定', 5, '这研究方向有问题啊，讲的基本是导航系统、mems，理论课偏多，老师很好，会顾及同学们的感受', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0006', 'offering-009', '历史共享表', '重', '不确定', '不确定', 4, '任务量大，慎重慎重', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0007', 'offering-010', '历史共享表', '不确定', '不确定', '不确定', 4, '数学课，但挺有意思，讲的东西也很实用，在这个领域很基础，放到相关领域也差不多能用', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0008', 'offering-011', '历史共享表', '不确定', '不确定', '不确定', 4, '光学实验课，任务量取决于调光路时间，最好有基物光学基础', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0009', 'offering-012', '历史共享表', '不确定', '不确定', '不确定', 5, '和另一个老师合开，另一个老师做声音滤波，尉老师做气体浓度的激光传感器，主要是光学传感方向。老师和学长人很好，内容有点点复杂，可能需要一定的基物3知识', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0010', 'offering-012', '历史共享表', '不确定', '不确定', '不确定', 4, '如果今年不变的话会有三个内容。第一个是曾理江老师主讲的全息光栅的制作，带大家制作光栅并且测量光栅周期。第二个内容是激光远程多普勒侦听，利用多普勒效应完整振动检测。前置知识是多普勒效应，课程中会涉及到一小部分的MATLAB信号处理内容。第三部分是尉昊赟老师主讲的激光吸收光谱检测，会带大家看直接吸收光谱（DAS）和波长调制光谱（WMS）的原理与具体实验，实验中会讲述LabVIEW的使用，大家会实现一个锁相解调。整体方向为光学测量与传感，偏向工程应用。在动手操作中提升能力。', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0011', 'offering-013', '历史共享表', '不确定', '不确定', '作业', 4, '和朱均孔令杰老师合开，基本就是介绍各自研究方向，平时没作业非常水', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0012', 'offering-014', '历史共享表', '不确定', '不确定', '不确定', 4, '主要内容是给机器狗做编程，但是使用的机械狗年代久远，有好多库没有安装或者版本太老，调试起来90%的时间都花在配环境上，比较坐牢（也许这也是一种锻炼）', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0013', 'offering-015', '历史共享表', '不确定', '不确定', '作业', 5, '课程内容主要是超透镜、光镊、激光加工、超分辨成像的原理讲解与实验，上课内容比较扎实，任务主要为研究报告的攥写且字数无强制要求，当水课能学一定东西，想深入探究老师也会给予一定的支持。而且助教人都超好，在作业中批注的问题基本都有回复，也会帮助进行实验准备。总体而言比较推荐', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0014', 'offering-017', '历史共享表', '不确定', '不确定', '不确定', 5, '以实验为主，每个实验两到三课时完成，最后一个是微流控芯片制作 。都是助教带领，每次实验前会有理论的讲解，不过助教有的很💩有的很负责，整体比较推荐，', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0015', 'offering-018', '历史共享表', '轻', '不确定', '不确定', 4, '任务量小，适合放松身心（bushi', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0016', 'offering-018', '历史共享表', '不确定', '不确定', '不确定', 4, '任务基本就是去看看实验室，动手玩两下，没有任何任务，不想花时间的可以考虑（）', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0017', 'offering-019', '历史共享表', '不确定', '不确定', '不确定', 5, '【推荐大一】几个老师合开，注意拼手速二级选课选方向（医学影像、神经工程，微纳医学，按照往年信息来看神经最火），没有基础要求，而且比较好玩，比较适合大一同学入手，', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0018', 'offering-019', '历史共享表', '不确定', '不确定', '不确定', 4, '微纳医学方向，目前看来很水（）', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0019', 'offering-019', '历史共享表', '不确定', '不确定', '作业', 5, '神经工程方向，平时课很水，虽然会讲一堆理论且听不懂，但是好消息是听不懂也没事。课程衔接好像有点问题，不同老师会把同一个事情反复讲。大作业是小组合作做一个mri的数据分析，助教很好基本会给你把代码都给你，可以直接开摆，但是想继续深入做的会因为小组合作的形式而相当赤石', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0020', 'offering-021', '历史共享表', '不确定', '不确定', '不确定', 4, '另外我记得有教大家怎么养细胞的环节，不知道现在是什么流程', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0021', 'offering-023', '历史共享表', '不确定', '不确定', '不确定', 4, '基本是一节讲座一节实验的形式最后留2周安排做最后实验，做多少学多少看自己意愿，实验设计都比较有意思，不需要有太好的电路基础。课程内容和老师自己研究方向相关性不强，如果想对整个集电方向有个大概的了解很建议选。', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0022', 'offering-024', '历史共享表', '不确定', '不确定', '不确定', 4, '大水课', array[]::text[], '', 'published', '2026-05-22');
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0023', 'offering-024', '历史共享表', '不确定', '不确定', '不确定', 5, '想学东西的话建议有电电基础的同学选修，当半个电电实验+半个cad习题课上，无电电基础的跟着操作手册走也能做出东西，当通识水课上。
insert into reviews (id, offering_id, term, workload, grading, assessment, rating, content, tags, contact, status, created_at) values ('review-0024', 'offering-025', '历史共享表', '不确定', '不确定', '不确定', 4, '内容主要是给机器狗进行简单编程和图像的处理，任务量适中。', array[]::text[], '', 'published', '2026-05-22');
